var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"천장이 무너지다니 하마터면 큰일날 뻔했네요.","JPN":"天井が崩れるなんて、危ないところでしたね。","ENG":"The ceiling collapsed? That was a close one.","TWN":"天花板竟然塌了，差點出大事。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어디 다친 데는 없으셨어요? 좋은 연고를 만드는 비법을 알아 왔답니다.","JPN":"お怪我はありませんか？　よく効く塗り薬を作る秘訣を調べてきました。","ENG":"Are you hurt anywhere? We learned how to make an excellent healing ointment.","TWN":"你沒受傷吧？聽説有找到製作藥膏的方法。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"걱정 마세요, 에델. 저도 카운터랍니다. 머리에 혹이 난 정도예요.","JPN":"心配いりませんわ、エデル。私もカウンターですから。頭にたんこぶができた程度です。","ENG":"No need, Edel. I am also a Counter. It is just a minor bump on the head.","TWN":"別擔心，艾瑟兒。我也是制裁者。不過就是頭上有個包而已。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 정도로 끝나서 다행이에요.","JPN":"その程度で済んで幸いでした。","ENG":"Thank goodness it only ended at that.","TWN":"幸好傷得不重。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 밤에 편히 주무실 수 있겠네요. 벽 속에서 들리던 소음의 원인이 사라졌으니까요.","JPN":"ですが、これで夜ぐっすりお休みになれますね。壁の中から聞こえていた騒音のもとが消えたのですから。","ENG":"But at least you'll be able to sleep soundly now. The cause of the noises within the walls is gone now.","TWN":"不過晚上你總算可以睡個好覺了。因為已經解決掉了在牆裡雜音的來源。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님도 자주 쥐덫을 사다 놓으셨잖아요?","JPN":"レジーナ様もよくネズミ取りを用意されてたじゃないですか。","ENG":"You used to buy and lay out mouse traps, didn't you?","TWN":"蕾佳娜不是也經常買捕鼠器嘛？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저도 그러길 바라지만…… 한동안 꿈자리가 사나울 것 같아요.","JPN":"私もそうであってほしいですけど……しばらくは夢見が悪そうですわ。","ENG":"I wish that were true, but... I believe my dreams will not be so pleasant for a while now.","TWN":"希望如此吧……不過我總感覺會做很長時間的噩夢。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"수로에서 오래된 유품들을 찾았습니다. 선조들이 영지를 다스리던 시절에 갇힌 사람들이었겠죠.","JPN":"水路で古い遺品を見つけました。ご先祖様が領地を治めていた頃に閉じ込められた人々だったのでしょう。","ENG":"We found old relics in the waterway. They are from the people who were trapped down there generations ago.","TWN":"我在水道裡找到了古老的遺物。應該都是先祖們統治領地時期囚禁的人吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러게요. 정말 안타까운 일이에요.","JPN":"そうですね。実に残念なお話です。","ENG":"Yes... It is a shame indeed.","TWN":"是啊，我也對此深表遺憾。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"두 분과 마주친 잔해들은 오래 전에 돌아가신 분들의 유골에서 희귀한 지식을 포식했을 텐데요.","JPN":"お二人が戦った残骸は昔亡くなった方々の遺骨から貴重な知識を捕食したはずです。","ENG":"The Remains you both encountered over there must feast on some rare knowledge from those old relics.","TWN":"兩位遇到的殘骸，應該從很久以前去世的人們的遺骨中享用到珍貴的知識吧。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 진미를 맛도 못 보고 떠나보내다니…….","JPN":"そんな珍味を、味わうこともなく倒してしまうなんて……","ENG":"What a pity that we couldn't taste them...","TWN":"只可惜我都還沒嚐到就……"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"참, 다른 분들 앞에서 입맛을 다시는 건 숙녀답지 못한 행위였죠.","JPN":"まあ、他の方々の前で舌なめずりをするのは淑女らしくない行為でしたね。","ENG":"Oh! How unladylike of us to be smacking our lips in front of others.","TWN":"哎呀，在大家面前表現出嘴饞的樣子可不是淑女所為。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……에델, 제 얘기는 애도를 표하자는 의미였어요.","JPN":"……エデル、私の話は哀悼しようという意味でしたのよ。","ENG":"...Edel, what I meant was that we show our condolences.","TWN":"……艾瑟兒，我的意思是讓你表示哀悼。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 나 보면서 다시지만 마. 보통 사람은 트라우마 걸린다구.","JPN":"あはは、アタシを見ながらはやらないでね。普通の人間はトラウマになっちゃうよ。","ENG":"Ahaha! Just don't look at me while you're doing it. But for normal people, they'll be traumatized.","TWN":"哈哈哈，不要看著我擦口水，要是換作一般人肯定會嚇壞。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그보다 레지나, 감기 기운은 좀 어때?","JPN":"それよりレジーナ、風邪の具合はどう？","ENG":"But enough about that. What about you, Regina? How are you feeling?","TWN":"對了，蕾佳娜，你感冒好點了嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기침은 많이 잦아들었어요. 그 아이가 준 열매가 몸에 잘 맞나 봐요.","JPN":"咳はだいぶ収まりましたわ。あの子がくれた木の実がよく効いたみたいです。","ENG":"The coughs lessened. I think those fruits that girl gave me are helping.","TWN":"咳嗽舒緩很多。那孩子給的果實好像很管用。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럼 오늘은 이만 쉬시는 편이 어떨까요? 무리하면 더 심해질 수도 있답니다.","JPN":"それでは今日はもうお休みになってはいかがですか？　無理するともっとひどくなるかもしれません。","ENG":"You should rest for the rest of the day. It might get worse if you stress yourself out too much.","TWN":"那今天就休息一下吧？硬撐的話，感冒可能會變得更嚴重。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 지금 읽고 있는 서신들은 오늘 중으로 답장을 보내야 해요.","JPN":"いいえ。今読んでいる手紙は今日中に返事をしないといけませんので。","ENG":"I cannot. I have to write a response to all the messages I am reading by today.","TWN":"不行。我現在看的這些信，今天之內都得寫好回信。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};